const axios = require('axios');
// 或者使用 Node.js 18+ 的 fetch API

/**
 * 万相-图像生成与编辑2.6 API调用示例
 * @param {Object} options - 调用参数
 * @param {string} options.apiKey - API密钥
 * @param {string} options.prompt - 提示词
 * @param {string} options.imageUrl - 参考图片URL
 * @param {string} options.size - 图片尺寸
 * @param {boolean} options.watermark - 是否添加水印
 * @param {number} options.n - 生成图片数量
 * @param {string} options.region - 地域（cn-beijing, ap-southeast-1, us-east-1）
 */
async function callWanxImageGeneration(options) {
    const {
        apiKey,
        prompt = "生成一张美丽的日落海滩场景",
        imageUrl = "https://example.com/reference-image.jpg",
        size = "1K",
        watermark = false,
        n = 1,
        region = "cn-beijing"
    } = options;

    // 根据地域选择API端点
    const endpoints = {
        'cn-beijing': 'https://dashscope.aliyuncs.com/api/v1/services/aigc/multimodal-generation/generation',
        'ap-southeast-1': 'https://dashscope-intl.aliyuncs.com/api/v1/services/aigc/multimodal-generation/generation',
        'us-east-1': 'https://dashscope-us.aliyuncs.com/api/v1/services/aigc/multimodal-generation/generation'
    };

    const endpoint = endpoints[region];
    if (!endpoint) {
        throw new Error(`不支持的地域: ${region}，请选择 cn-beijing, ap-southeast-1 或 us-east-1`);
    }

    // 构建请求数据
    const requestData = {
        model: "wan2.6-image",
        input: {
            messages: [
                {
                    role: "user",
                    content: [
                        {
                            text: prompt
                        },
                        {
                            image: `data:image/jpeg;base64,`
                        },
                      //   {
                      //       image: `data:image/jpeg;base64,`
                      //   },
                      //   {
                      //       image: `data:image/jpeg;base64,`
                      //   },
                      //   {
                      //  image: `data:image/jpeg;base64,`
                      //   }
                    ]
                }
            ]
        },
        parameters: {
            prompt_extend: true,
            watermark: watermark,
            n: n,
            enable_interleave: false,
            size: size,
            negative_prompt: "低分辨率，模糊，画面混乱，人物畸形",
            seed: Math.floor(Math.random() * 1000000) // 随机种子
        }
    };

    try {
        console.log('正在调用万相图像生成API...');
        const response = await fetch(endpoint, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify(requestData),
            signal: AbortSignal.timeout(120000)
        });

        // 处理 HTTP 错误状态
        if (!response.ok) {
            throw new Error(`HTTP错误: ${response.status} ${response.statusText}`);
        }

        const result = await response.json();
        
        // const response = await axios.post(endpoint, requestData, {
        //     headers: {
        //         'Content-Type': 'application/json',
        //         'Authorization': `Bearer ${apiKey}`
        //     },
        //     timeout: 120000 // 120秒超时，图像生成可能需要较长时间
        // });

        // if (response.status === 200) {
        //     const result = response.data;
            
            if (result.output && result.output.choices) {
                console.log('图像生成成功！');
                console.log(`请求ID: ${result.request_id}`);
                console.log(`生成图片数量: ${result.usage.image_count}`);
                console.log(`图片尺寸: ${result.usage.size}`);
                
                // 提取所有生成的图片URL
                const imageUrls = [];
                result.output.choices.forEach((choice, index) => {
                    choice.message.content.forEach(content => {
                        if (content.type === "image") {
                            console.log(`图片${index + 1} URL: ${content.image}`);
                            imageUrls.push({
                                url: content.image,
                                index: index + 1
                            });
                        }
                    });
                });
                
                return {
                    success: true,
                    requestId: result.request_id,
                    imageCount: result.usage.image_count,
                    imageSize: result.usage.size,
                    imageUrls: imageUrls,
                    rawResponse: result
                };
            } else {
                throw new Error('API响应格式异常');
            }
        // } else {
        //     throw new Error(`HTTP错误: ${response.status}`);
        // }
    } catch (error) {
        console.error('调用API失败:', error.message);
        
        if (error.response) {
            console.error('错误响应:', error.response.data);
            return {
                success: false,
                error: error.response.data.message || error.response.data.code,
                code: error.response.data.code,
                requestId: error.response.data.request_id
            };
        }
        
        return {
            success: false,
            error: error.message
        };
    }
}

/**
 * 异步调用示例（适用于需要长时间处理的任务）
 */
async function callWanxImageGenerationAsync(options) {
    const {
        apiKey,
        prompt,
        imageUrl,
        size = "1K",
        watermark = false,
        n = 1,
        region = "cn-beijing"
    } = options;

    const asyncEndpoints = {
        'cn-beijing': 'https://dashscope.aliyuncs.com/api/v1/services/aigc/image-generation/generation',
        'ap-southeast-1': 'https://dashscope-intl.aliyuncs.com/api/v1/services/aigc/image-generation/generation',
        'us-east-1': 'https://dashscope-us.aliyuncs.com/api/v1/services/aigc/image-generation/generation'
    };

    const endpoint = asyncEndpoints[region];
    if (!endpoint) {
        throw new Error(`不支持的地域: ${region}`);
    }

    const requestData = {
        model: "wan2.6-image",
        input: {
            messages: [
                {
                    role: "user",
                    content: [
                        {
                            text: prompt
                        },
                        {
                            image: imageUrl
                        }
                    ]
                }
            ]
        },
        parameters: {
            prompt_extend: true,
            watermark: watermark,
            n: n,
            enable_interleave: false,
            size: size
        }
    };

    try {
        console.log('创建异步任务...');
        
        const response = await axios.post(endpoint, requestData, {
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`,
                'X-DashScope-Async': 'enable'
            }
        });

        if (response.status === 200 && response.data.output.task_id) {
            const taskId = response.data.output.task_id;
            console.log(`任务创建成功，任务ID: ${taskId}`);
            
            return {
                success: true,
                taskId: taskId,
                requestId: response.data.request_id
            };
        } else {
            throw new Error('异步任务创建失败');
        }
    } catch (error) {
        console.error('创建异步任务失败:', error.message);
        return {
            success: false,
            error: error.message
        };
    }
}

/**
 * 查询异步任务结果
 */
async function queryAsyncTaskResult(apiKey, taskId, region = "cn-beijing") {
    const queryEndpoints = {
        'cn-beijing': `https://dashscope.aliyuncs.com/api/v1/tasks/${taskId}`,
        'ap-southeast-1': `https://dashscope-intl.aliyuncs.com/api/v1/tasks/${taskId}`,
        'us-east-1': `https://dashscope-us.aliyuncs.com/api/v1/tasks/${taskId}`
    };

    const endpoint = queryEndpoints[region];
    
    try {
        const response = await axios.get(endpoint, {
            headers: {
                'Authorization': `Bearer ${apiKey}`
            }
        });

        if (response.status === 200) {
            const result = response.data;
            const taskStatus = result.output.task_status;
            
            console.log(`任务状态: ${taskStatus}`);
            
            if (taskStatus === 'SUCCEEDED') {
                const imageUrls = [];
                if (result.output.choices) {
                    result.output.choices.forEach((choice, index) => {
                        choice.message.content.forEach(content => {
                            if (content.type === "image") {
                                console.log(`图片${index + 1} URL: ${content.image}`);
                                imageUrls.push(content.image);
                            }
                        });
                    });
                }
                
                return {
                    success: true,
                    status: taskStatus,
                    imageUrls: imageUrls,
                    imageCount: result.usage?.image_count || 0,
                    rawResponse: result
                };
            } else if (taskStatus === 'PENDING' || taskStatus === 'RUNNING') {
                return {
                    success: true,
                    status: taskStatus,
                    message: '任务处理中，请稍后查询'
                };
            } else {
                return {
                    success: false,
                    status: taskStatus,
                    error: '任务处理失败'
                };
            }
        }
    } catch (error) {
        console.error('查询任务结果失败:', error.message);
        return {
            success: false,
            error: error.message
        };
    }
}

/**
 * 使用示例
 */
async function main() {
    // 配置参数
    const config = {
        apiKey: 'sk-xxx', // 替换为您的API Key
        prompt: '参考这张图片的风格，生成一个美丽的日落海滩场景',
        imageUrl: 'https://example.com/reference-image.jpg', // 替换为实际图片URL
        size: '1K',
        watermark: false,
        n: 1,
        region: 'cn-beijing'
    };

    // 方法1：同步调用
    console.log('=== 同步调用示例 ===');
    const syncResult = await callWanxImageGeneration(config);
    
    if (syncResult.success) {
        console.log('同步调用成功！');
        // 这里可以添加下载图片的代码
    } else {
        console.error('同步调用失败:', syncResult.error);
    }

    // 方法2：异步调用（适用于长时间任务）
    console.log('\n=== 异步调用示例 ===');
    const asyncResult = await callWanxImageGenerationAsync(config);
    
    if (asyncResult.success) {
        console.log('异步任务创建成功，开始轮询结果...');
        
        // 轮询查询结果
        let maxAttempts = 30; // 最多尝试30次
        let attempt = 0;
        
        while (attempt < maxAttempts) {
            attempt++;
            console.log(`第${attempt}次查询...`);
            
            const queryResult = await queryAsyncTaskResult(
                config.apiKey, 
                asyncResult.taskId, 
                config.region
            );
            
            if (queryResult.success) {
                if (queryResult.status === 'SUCCEEDED') {
                    console.log('异步任务完成！');
                    console.log(`生成图片数量: ${queryResult.imageCount}`);
                    break;
                } else if (queryResult.status === 'FAILED') {
                    console.error('异步任务失败');
                    break;
                } else {
                    // 任务还在处理中，等待5秒后重试
                    await new Promise(resolve => setTimeout(resolve, 5000));
                }
            } else {
                console.error('查询失败:', queryResult.error);
                break;
            }
        }
        
        if (attempt >= maxAttempts) {
            console.log('轮询超时，任务可能仍在处理中');
        }
    } else {
        console.error('异步任务创建失败:', asyncResult.error);
    }
}

// 导出模块
module.exports = {
    callWanxImageGeneration,
    callWanxImageGenerationAsync,
    queryAsyncTaskResult
};

// 如果直接运行此文件
if (require.main === module) {
    main().catch(console.error);
}
